import React, { useState, useEffect, useRef } from 'react';
import Chart from 'chart.js/auto';
import { api } from '../api';
import { useToast } from '../hooks/useToast';
import Toast from './Toast';

const Dashboard = ({ token }) => {
  const [metricas, setMetricas] = useState(null);
  const [tendencia, setTendencia] = useState(null);
  const [loading, setLoading] = useState(true);
  const [vistaActiva, setVistaActiva] = useState('metricas');
  const [tabReportes, setTabReportes] = useState('pendientes');
  const [reportesPendientes, setReportesPendientes] = useState([]);
  const [todosReportes, setTodosReportes] = useState([]);
  const [mostrarFormulario, setMostrarFormulario] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);
  const [reporteEditando, setReporteEditando] = useState(null);
  const { toasts, removeToast, toast } = useToast();

  const FORM_INICIAL = {
    latitud: 10.3910,
    longitud: -75.4794,
    fecha_hora: new Date().toISOString().slice(0, 16),
    gravedad: 'leve',
    tipo_vehiculo: 'automovil',
    clima: 'soleado',
    estado_via: 'bueno',
    dia_festivo: false,
    hora_pico: false,
    descripcion: '',
  };
  const [nuevoAccidente, setNuevoAccidente] = useState(FORM_INICIAL);

  const chartGravedadRef = useRef(null);
  const chartClimaRef = useRef(null);
  const chartTendenciaRef = useRef(null);
  const instanceGravedad = useRef(null);
  const instanceClima = useRef(null);
  const instanceTendencia = useRef(null);

  useEffect(() => {
    cargarTodo();
    const interval = setInterval(cargarTodo, 30000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (metricas && tendencia && vistaActiva === 'metricas') {
      crearGraficos();
    }
    return () => {
      instanceGravedad.current?.destroy();
      instanceClima.current?.destroy();
      instanceTendencia.current?.destroy();
    };
  }, [metricas, tendencia, vistaActiva]);

  const cargarTodo = async () => {
    await Promise.all([
      cargarMetricas(),
      cargarTendencia(),
      cargarReportesPendientes(),
      cargarTodosReportes(),
    ]);
  };

  const cargarMetricas = async () => {
    try {
      const data = await api.get('/api/metricas/dashboard');
      setMetricas(data);
      setLoading(false);
    } catch (error) {
      console.error('Error cargando métricas:', error);
      setLoading(false);
    }
  };

  const cargarTendencia = async () => {
    try {
      const data = await api.get('/api/metricas/tendencia-mensual');
      setTendencia(data);
    } catch (error) {
      console.error('Error cargando tendencia:', error);
    }
  };

  const cargarReportesPendientes = async () => {
    try {
      const data = await api.get('/api/reportes/pendientes');
      setReportesPendientes(data);
    } catch (error) {
      console.error('Error cargando reportes pendientes:', error);
    }
  };

  const cargarTodosReportes = async () => {
    try {
      const data = await api.get('/api/accidentes');
      setTodosReportes(data);
    } catch (error) {
      console.error('Error cargando reportes:', error);
    }
  };

  const aprobarReporte = async (id) => {
    try {
      await api.put(`/api/reportes/${id}/aprobar`);
      toast.success('Reporte aprobado exitosamente');
      cargarTodo();
    } catch (error) {
      toast.error(`Error al aprobar: ${error.message}`);
    }
  };

  const rechazarReporte = async (id) => {
    if (!window.confirm('¿Estás seguro de rechazar este reporte?')) return;
    try {
      await api.put(`/api/reportes/${id}/rechazar`);
      toast.warning('Reporte rechazado');
      cargarReportesPendientes();
    } catch (error) {
      toast.error(`Error al rechazar: ${error.message}`);
    }
  };

  const editarReporte = (reporte) => {
    setModoEdicion(true);
    setReporteEditando(reporte);
    setNuevoAccidente({
      latitud: reporte.latitud,
      longitud: reporte.longitud,
      fecha_hora: new Date(reporte.fecha_hora).toISOString().slice(0, 16),
      gravedad: reporte.gravedad,
      tipo_vehiculo: reporte.tipo_vehiculo,
      clima: reporte.clima,
      estado_via: reporte.estado_via,
      dia_festivo: reporte.dia_festivo || false,
      hora_pico: reporte.hora_pico || false,
      descripcion: reporte.descripcion || '',
    });
    setMostrarFormulario(true);
  };

  const eliminarReporte = async (id) => {
    if (!window.confirm('¿Estás seguro de eliminar este reporte permanentemente?')) return;
    try {
      await api.delete(`/api/accidentes/${id}`);
      toast.info('Reporte eliminado');
      cargarTodo();
    } catch (error) {
      toast.error(`Error al eliminar: ${error.message}`);
    }
  };

  const handleSubmitAccidente = async (e) => {
    e.preventDefault();
    try {
      if (modoEdicion) {
        await api.put(`/api/accidentes/${reporteEditando.id}`, nuevoAccidente);
        toast.success('Accidente actualizado exitosamente');
      } else {
        await api.post('/api/accidentes', nuevoAccidente);
        toast.success('Accidente registrado exitosamente');
      }
      setMostrarFormulario(false);
      setModoEdicion(false);
      setReporteEditando(null);
      setNuevoAccidente(FORM_INICIAL);
      cargarTodo();
    } catch (error) {
      toast.error(`Error al guardar: ${error.message}`);
    }
  };

  const crearGraficos = () => {
    if (chartGravedadRef.current) {
      instanceGravedad.current?.destroy();
      instanceGravedad.current = new Chart(chartGravedadRef.current.getContext('2d'), {
        type: 'doughnut',
        data: {
          labels: ['Leves', 'Graves', 'Fatales'],
          datasets: [{
            data: [
              metricas.por_gravedad.leve || 0,
              metricas.por_gravedad.grave || 0,
              metricas.por_gravedad.fatal || 0,
            ],
            backgroundColor: ['#4CAF50', '#FF9800', '#F44336'],
            borderWidth: 2,
            borderColor: '#fff',
          }],
        },
        options: {
          responsive: true,
          maintainAspectRatio: false,
          plugins: {
            legend: { position: 'bottom' },
            title: { display: true, text: 'Accidentes por Gravedad' },
          },
        },
      });
    }

    if (chartClimaRef.current) {
      instanceClima.current?.destroy();
      instanceClima.current = new Chart(chartClimaRef.current.getContext('2d'), {
        type: 'bar',
        data: {
          labels: Object.keys(metricas.por_clima),
          datasets: [{
            label: 'Accidentes',
            data: Object.values(metricas.por_clima),
            backgroundColor: ['#FFD700', '#87CEEB', '#4169E1', '#9E9E9E'],
            borderWidth: 1,
          }],
        },
        options: {
          responsive: true,
          maintainAspectRatio: false,
          plugins: {
            legend: { display: false },
            title: { display: true, text: 'Accidentes por Condición Climática' },
          },
          scales: { y: { beginAtZero: true } },
        },
      });
    }

    if (chartTendenciaRef.current && tendencia?.datos?.length > 0) {
      instanceTendencia.current?.destroy();
      instanceTendencia.current = new Chart(chartTendenciaRef.current.getContext('2d'), {
        type: 'line',
        data: {
          labels: tendencia.datos.map((d) => d.etiqueta),
          datasets: [{
            label: 'Accidentes',
            data: tendencia.datos.map((d) => d.total),
            borderColor: '#2196F3',
            backgroundColor: 'rgba(33, 150, 243, 0.1)',
            tension: 0.4,
            fill: true,
            pointBackgroundColor: '#2196F3',
            pointRadius: 5,
          }],
        },
        options: {
          responsive: true,
          maintainAspectRatio: false,
          plugins: {
            title: { display: true, text: 'Tendencia de Accidentes (Últimos 12 meses)' },
          },
          scales: { y: { beginAtZero: true, ticks: { stepSize: 1 } } },
        },
      });
    }
  };

  if (loading) {
    return <div className="loading">Cargando dashboard...</div>;
  }

  return (
    <div className="dashboard">
      <Toast toasts={toasts} onRemove={removeToast} />

      <div className="dashboard-header">
        <h2>📊 Panel de Control — Administrador</h2>
        <div className="dashboard-actions">
          <button
            className={`btn-tab ${vistaActiva === 'metricas' ? 'active' : ''}`}
            onClick={() => setVistaActiva('metricas')}
          >
            📈 Métricas
          </button>
          <button
            className={`btn-tab ${vistaActiva === 'reportes' ? 'active' : ''}`}
            onClick={() => setVistaActiva('reportes')}
          >
            📋 Reportes {reportesPendientes.length > 0 && `(${reportesPendientes.length})`}
          </button>
          <button
            className="btn-primary"
            onClick={() => {
              setModoEdicion(false);
              setReporteEditando(null);
              setNuevoAccidente(FORM_INICIAL);
              setMostrarFormulario(!mostrarFormulario);
            }}
          >
            {mostrarFormulario ? '❌ Cancelar' : '➕ Nuevo Accidente'}
          </button>
        </div>
      </div>

      {mostrarFormulario && (
        <div className="formulario-accidente">
          <h3>{modoEdicion ? '✏️ Editar Reporte' : '📝 Nuevo Reporte de Accidente'}</h3>
          <form onSubmit={handleSubmitAccidente}>
            <div className="form-grid">
              <div className="form-group">
                <label>Latitud:</label>
                <input type="number" step="0.000001" value={nuevoAccidente.latitud}
                  onChange={(e) => setNuevoAccidente({ ...nuevoAccidente, latitud: parseFloat(e.target.value) })}
                  required />
              </div>
              <div className="form-group">
                <label>Longitud:</label>
                <input type="number" step="0.000001" value={nuevoAccidente.longitud}
                  onChange={(e) => setNuevoAccidente({ ...nuevoAccidente, longitud: parseFloat(e.target.value) })}
                  required />
              </div>
              <div className="form-group">
                <label>Fecha y Hora:</label>
                <input type="datetime-local" value={nuevoAccidente.fecha_hora}
                  onChange={(e) => setNuevoAccidente({ ...nuevoAccidente, fecha_hora: e.target.value })}
                  required />
              </div>
              <div className="form-group">
                <label>Gravedad:</label>
                <select value={nuevoAccidente.gravedad}
                  onChange={(e) => setNuevoAccidente({ ...nuevoAccidente, gravedad: e.target.value })}>
                  <option value="leve">Leve</option>
                  <option value="grave">Grave</option>
                  <option value="fatal">Fatal</option>
                </select>
              </div>
              <div className="form-group">
                <label>Tipo de Vehículo:</label>
                <select value={nuevoAccidente.tipo_vehiculo}
                  onChange={(e) => setNuevoAccidente({ ...nuevoAccidente, tipo_vehiculo: e.target.value })}>
                  <option value="automovil">Automóvil</option>
                  <option value="moto">Moto</option>
                  <option value="bus">Bus</option>
                  <option value="camion">Camión</option>
                  <option value="bicicleta">Bicicleta</option>
                </select>
              </div>
              <div className="form-group">
                <label>Clima:</label>
                <select value={nuevoAccidente.clima}
                  onChange={(e) => setNuevoAccidente({ ...nuevoAccidente, clima: e.target.value })}>
                  <option value="soleado">Soleado</option>
                  <option value="nublado">Nublado</option>
                  <option value="lluvia">Lluvia</option>
                </select>
              </div>
              <div className="form-group">
                <label>Estado de la Vía:</label>
                <select value={nuevoAccidente.estado_via}
                  onChange={(e) => setNuevoAccidente({ ...nuevoAccidente, estado_via: e.target.value })}>
                  <option value="bueno">Bueno</option>
                  <option value="regular">Regular</option>
                  <option value="malo">Malo</option>
                </select>
              </div>
              <div className="form-group checkbox-group">
                <label>
                  <input type="checkbox" checked={nuevoAccidente.dia_festivo}
                    onChange={(e) => setNuevoAccidente({ ...nuevoAccidente, dia_festivo: e.target.checked })} />
                  Día festivo
                </label>
              </div>
              <div className="form-group checkbox-group">
                <label>
                  <input type="checkbox" checked={nuevoAccidente.hora_pico}
                    onChange={(e) => setNuevoAccidente({ ...nuevoAccidente, hora_pico: e.target.checked })} />
                  Hora pico
                </label>
              </div>
            </div>
            <div className="form-group full-width">
              <label>Descripción:</label>
              <textarea value={nuevoAccidente.descripcion}
                onChange={(e) => setNuevoAccidente({ ...nuevoAccidente, descripcion: e.target.value })}
                rows="3" placeholder="Descripción detallada del accidente..." />
            </div>
            <button type="submit" className="btn-submit">
              {modoEdicion ? '💾 Actualizar Reporte' : '💾 Guardar Reporte'}
            </button>
          </form>
        </div>
      )}

      {vistaActiva === 'metricas' && metricas && (
        <>
          <div className="metricas-cards">
            <div className="metric-card total">
              <div className="metric-icon">📈</div>
              <div className="metric-content">
                <h3>Total Accidentes</h3>
                <p className="metric-value">{metricas.total_accidentes}</p>
              </div>
            </div>
            <div className="metric-card mes">
              <div className="metric-icon">📅</div>
              <div className="metric-content">
                <h3>Este Mes</h3>
                <p className="metric-value">{metricas.accidentes_mes_actual}</p>
              </div>
            </div>
            <div className="metric-card tasa">
              <div className="metric-icon">📊</div>
              <div className="metric-content">
                <h3>Tasa Mensual</h3>
                <p className="metric-value">
                  {metricas.total_accidentes > 0
                    ? ((metricas.accidentes_mes_actual / metricas.total_accidentes) * 100).toFixed(1)
                    : 0}%
                </p>
              </div>
            </div>
            <div className="metric-card criticos">
              <div className="metric-icon">⚠️</div>
              <div className="metric-content">
                <h3>Críticos</h3>
                <p className="metric-value">
                  {(metricas.por_gravedad.grave || 0) + (metricas.por_gravedad.fatal || 0)}
                </p>
              </div>
            </div>
          </div>

          <div className="graficos-container">
            <div className="grafico-card">
              <canvas ref={chartGravedadRef}></canvas>
            </div>
            <div className="grafico-card">
              <canvas ref={chartClimaRef}></canvas>
            </div>
            <div className="grafico-card full-width">
              {tendencia?.datos?.length > 0
                ? <canvas ref={chartTendenciaRef}></canvas>
                : <div className="sin-datos-tendencia">
                    <p>📭 No hay suficientes datos históricos para mostrar la tendencia mensual.</p>
                  </div>
              }
            </div>
          </div>

          <div className="predicciones-section">
            <h3>🔮 Alertas del Sistema</h3>
            <div className="alertas-grid">
              {(metricas.por_gravedad.fatal || 0) > 0 && (
                <div className="alerta warning">
                  <span className="alerta-icon">⚠️</span>
                  <div>
                    <h4>Accidentes Fatales</h4>
                    <p>Se han registrado {metricas.por_gravedad.fatal} accidentes fatales en el sistema.</p>
                  </div>
                </div>
              )}
              <div className="alerta info">
                <span className="alerta-icon">ℹ️</span>
                <div>
                  <h4>Vehículos más involucrados</h4>
                  <p>
                    {Object.entries(metricas.por_vehiculo || {}).sort((a, b) => b[1] - a[1])[0]
                      ? `${Object.entries(metricas.por_vehiculo).sort((a, b) => b[1] - a[1])[0][0]}: ${Object.entries(metricas.por_vehiculo).sort((a, b) => b[1] - a[1])[0][1]} accidentes registrados.`
                      : 'Sin datos de vehículos aún.'}
                  </p>
                </div>
              </div>
              <div className="alerta success">
                <span className="alerta-icon">✅</span>
                <div>
                  <h4>Sistema operativo</h4>
                  <p>Base de datos activa con {metricas.total_accidentes} registros aprobados.</p>
                </div>
              </div>
            </div>
          </div>
        </>
      )}

      {vistaActiva === 'reportes' && (
        <div className="gestion-reportes">
          <div className="reportes-tabs">
            <button
              className={`reporte-tab ${tabReportes === 'pendientes' ? 'active' : ''}`}
              onClick={() => setTabReportes('pendientes')}
            >
              📋 Pendientes ({reportesPendientes.length})
            </button>
            <button
              className={`reporte-tab ${tabReportes === 'todos' ? 'active' : ''}`}
              onClick={() => setTabReportes('todos')}
            >
              ✅ Todos ({todosReportes.length})
            </button>
          </div>

          {tabReportes === 'pendientes' && (
            <>
              {reportesPendientes.length === 0 ? (
                <div className="sin-reportes">
                  <span>✅</span>
                  <h3>No hay reportes pendientes</h3>
                  <p>Todos los reportes han sido revisados</p>
                </div>
              ) : (
                <div className="reportes-grid">
                  {reportesPendientes.map((reporte) => (
                    <div key={reporte.id} className="reporte-card-admin">
                      <div className="reporte-header-admin">
                        <div className="reporte-badge pendiente"><span>⏳</span> PENDIENTE</div>
                        <span className="reporte-fecha">
                          {new Date(reporte.fecha_hora).toLocaleString('es-CO')}
                        </span>
                      </div>
                      <div className="reporte-body-admin">
                        <div className="reporte-info-grid">
                          <div className="info-item-admin">
                            <span className="info-label">📍 Ubicación:</span>
                            <span className="info-value">{reporte.latitud.toFixed(5)}, {reporte.longitud.toFixed(5)}</span>
                          </div>
                          <div className="info-item-admin">
                            <span className="info-label">⚠️ Gravedad:</span>
                            <span className={`info-value gravedad-${reporte.gravedad}`}>{reporte.gravedad.toUpperCase()}</span>
                          </div>
                          <div className="info-item-admin">
                            <span className="info-label">🚗 Vehículo:</span>
                            <span className="info-value">{reporte.tipo_vehiculo}</span>
                          </div>
                          <div className="info-item-admin">
                            <span className="info-label">🌤️ Clima:</span>
                            <span className="info-value">{reporte.clima}</span>
                          </div>
                        </div>
                        {reporte.descripcion && (
                          <div className="reporte-descripcion-admin">
                            <strong>Descripción:</strong>
                            <p>{reporte.descripcion}</p>
                          </div>
                        )}
                      </div>
                      <div className="reporte-acciones-admin">
                        <button className="btn-aprobar-admin" onClick={() => aprobarReporte(reporte.id)}>✅ Aprobar</button>
                        <button className="btn-editar-admin" onClick={() => editarReporte(reporte)}>✏️ Editar</button>
                        <button className="btn-rechazar-admin" onClick={() => rechazarReporte(reporte.id)}>❌ Rechazar</button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </>
          )}

          {tabReportes === 'todos' && (
            <div className="todos-reportes-section">
              <div className="tabla-reportes">
                <table>
                  <thead>
                    <tr>
                      <th>ID</th>
                      <th>Fecha</th>
                      <th>Ubicación</th>
                      <th>Gravedad</th>
                      <th>Vehículo</th>
                      <th>Acciones</th>
                    </tr>
                  </thead>
                  <tbody>
                    {todosReportes.map((reporte) => (
                      <tr key={reporte.id}>
                        <td>#{reporte.id}</td>
                        <td>{new Date(reporte.fecha_hora).toLocaleDateString('es-CO')}</td>
                        <td>{reporte.latitud.toFixed(4)}, {reporte.longitud.toFixed(4)}</td>
                        <td>
                          <span className={`badge-gravedad ${reporte.gravedad}`}>{reporte.gravedad}</span>
                        </td>
                        <td>{reporte.tipo_vehiculo}</td>
                        <td>
                          <button className="btn-icon-admin" onClick={() => editarReporte(reporte)} title="Editar">✏️</button>
                          <button className="btn-icon-admin danger" onClick={() => eliminarReporte(reporte.id)} title="Eliminar">🗑️</button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default Dashboard;
